const FormRow = ({ label, children }: FormRowProps) => (
  <div className="row align-items-center mb-3">
    <label className="col-4 col-form-label text-end">
      {label}
    </label>
    <div className="col-8">
      {children}
    </div>
  </div>
);

export type CheckboxSectionProps<T> = {
  title: string;
  items: [keyof T, string][];
  form: T;
  toggle: (key: keyof T) => void;
};

export function CheckboxSection<T>({
  title,
  items,
  form,
  toggle,
}: CheckboxSectionProps<T>) {
  return (
    <>
      <h6 className="text-center mt-4 mb-2">{title}</h6>

      <div className="row">
        <div className="col-8 offset-4">
          {items.map(([key, label]) => (
            <div className="form-check mb-2" key={String(key)}>
              <input
                className="form-check-input"
                type="checkbox"
                checked={Boolean(form[key])}
                onChange={() => toggle(key)}
              />
              <label className="form-check-label">
                {label}
              </label>
            </div>
          ))}
        </div>
      </div>
    </>
  );
}
